/*
Definition of a node
struct Node {
    int data;
    struct Node *next;
};
*/

int searchElement(struct Node *head, int x) {
    int position = 1;
    struct Node *temp = head;

    while (temp != NULL) {
        if (temp->data == x) {
            return position;
        }
        temp = temp->next;
        position++;
    }
    return -1;
}
